import React, { useRef, useEffect, useState } from "react";
import * as faceapi from "face-api.js";
import axios from "axios";

const Scanner = () => {
  const videoRef = useRef();
  const [modelsLoaded, setModelsLoaded] = useState(false);
  const [consent, setConsent] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [lastResult, setLastResult] = useState(null);

  useEffect(() => {
    loadModels();
  }, []);

  const loadModels = async () => {
    try {
      setError("");
      const MODEL_URL = "/models";

      // Load all required models
      await Promise.all([
        faceapi.nets.tinyFaceDetector.loadFromUri(MODEL_URL),
        faceapi.nets.faceExpressionNet.loadFromUri(MODEL_URL),
        faceapi.nets.ageGenderNet.loadFromUri(MODEL_URL),
      ]);

      setModelsLoaded(true);
      console.log("All Models Loaded Successfully");
    } catch (err) {
      console.error("Error loading models:", err);
      setError("Failed to load models. Please refresh the page.");
    }
  };

  const startVideo = () => {
    navigator.mediaDevices
      .getUserMedia({ video: true })
      .then((stream) => {
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      })
      .catch((err) => {
        console.error("Error accessing webcam:", err);
        setError("Could not access webcam. Please allow camera permissions.");
      });
  };

  const detectFace = async () => {
    if (!modelsLoaded) {
      alert("Models are still loading...");
      return;
    }

    if (!videoRef.current || !videoRef.current.srcObject) {
      alert("Please start the video first");
      return;
    }

    setLoading(true);
    setError("");

    try {
      const detection = await faceapi
        .detectSingleFace(
          videoRef.current,
          new faceapi.TinyFaceDetectorOptions()
        )
        .withFaceExpressions()
        .withAgeAndGender();

      if (!detection) {
        setError("No face detected. Please position your face in front of the camera.");
        setLoading(false);
        return;
      }

      // Get the dominant emotion
      const expressions = detection.expressions;
      const emotion = Object.keys(expressions).reduce((a, b) =>
        expressions[a] > expressions[b] ? a : b
      );

      const result = {
        age: Math.round(detection.age),
        gender: detection.gender,
        emotion: emotion,
        confidence: Math.round(expressions[emotion] * 100)
      };

      setLastResult(result);

      // Send data to server
      await axios.post("http://localhost:5000/api/face-data", {
        age: result.age,
        gender: result.gender,
        emotion: result.emotion
      });

      alert(`Scan Complete!\nAge: ${result.age}\nGender: ${result.gender}\nEmotion: ${emotion} (${result.confidence}%)`);
    } catch (err) {
      console.error("Detection error:", err);
      setError("Error during face detection. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: "600px", margin: "0 auto" }}>
      <h2>Face Scanner</h2>

      {!consent && (
        <div style={{ padding: "20px", border: "1px solid #ccc", borderRadius: "8px", marginBottom: "20px" }}>
          <p><strong>Privacy Notice:</strong> This app uses facial analytics. No images are stored.</p>
          <button
            onClick={() => {
              setConsent(true);
              startVideo();
            }}
            style={{
              padding: "10px 20px",
              fontSize: "16px",
              backgroundColor: "#4CAF50",
              color: "white",
              border: "none",
              borderRadius: "5px",
              cursor: "pointer"
            }}
          >
            Agree & Start Camera
          </button>
        </div>
      )}

      {error && (
        <div style={{ 
          padding: "10px", 
          backgroundColor: "#ffebee", 
          color: "#c62828",
          borderRadius: "5px",
          marginBottom: "10px"
        }}>
          {error}
        </div>
      )}

      <div style={{ position: "relative", display: consent ? "block" : "none" }}>
        <video 
          ref={videoRef} 
          autoPlay 
          muted 
          playsInline
          style={{ width: "100%", borderRadius: "8px" }} 
        />

        {!modelsLoaded && (
          <div style={{
            position: "absolute",
            top: "50%",
            left: "50%",
            transform: "translate(-50%, -50%)",
            backgroundColor: "rgba(0,0,0,0.7)",
            color: "white",
            padding: "20px",
            borderRadius: "8px",
            textAlign: "center"
          }}>
            Loading AI Models...
          </div>
        )}
      </div>

      <div style={{ marginTop: "20px" }}>
        <button 
          onClick={detectFace} 
          disabled={!modelsLoaded || loading || !consent}
          style={{
            padding: "12px 30px",
            fontSize: "16px",
            backgroundColor: !modelsLoaded || loading ? "#ccc" : "#2196F3",
            color: "white",
            border: "none",
            borderRadius: "5px",
            cursor: !modelsLoaded || loading ? "not-allowed" : "pointer",
            marginRight: "10px"
          }}
        >
          {loading ? "Scanning..." : modelsLoaded ? "Scan Face" : "Loading Models..."}
        </button>

        {consent && (
          <button 
            onClick={() => {
              if (videoRef.current && videoRef.current.srcObject) {
                videoRef.current.srcObject.getTracks().forEach(track => track.stop());
              }
              setConsent(false);
              setLastResult(null);
            }}
            style={{
              padding: "12px 30px",
              fontSize: "16px",
              backgroundColor: "#f44336",
              color: "white",
              border: "none",
              borderRadius: "5px",
              cursor: "pointer"
            }}
          >
            Stop Camera
          </button>
        )}
      </div>

      {lastResult && (
        <div style={{ marginTop: "20px", padding: "15px", backgroundColor: "#e3f2fd", borderRadius: "8px" }}>
          <h3>Last Scan Result:</h3>
          <p><strong>Age:</strong> {lastResult.age}</p>
          <p><strong>Gender:</strong> {lastResult.gender}</p>
          <p><strong>Emotion:</strong> {lastResult.emotion} ({lastResult.confidence}%)</p>
        </div>
      )}
    </div>
  );
};

export default Scanner;
